/**
 * 飞书群消息发送工具
 * 使用 OpenClaw 配置的 appId/appSecret 获取 tenant_access_token 后发送消息
 */

const APP_ID = 'cli_a9458ff380b99ccb';
const APP_SECRET = 'Qs3NVp…OGKv';

async function getTenantAccessToken() {
  const res = await fetch('https://open.feishu.cn/open-apis/auth/v3/tenant_access_token/internal', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ app_id: APP_ID, app_secret: APP_SECRET }),
  });
  const data = await res.json();
  if (data.code !== 0) throw new Error(`Get token failed: ${JSON.stringify(data)}`);
  return data.tenant_access_token;
}

/**
 * 发送飞书群消息（富文本，支持 @ 提及）
 * @param {string} chatId - 群 chat_id，如 oc_xxx
 * @param {string} text - 消息文本（支持 <at user_id="xxx">name</at> 格式）
 */
export async function sendGroupMessage(chatId, text) {
  const token = await getTenantAccessToken();

  const res = await fetch('https://open.feishu.cn/open-apis/im/v1/messages?receive_id_type=chat_id', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${token}`,
    },
    body: JSON.stringify({
      receive_id: chatId,
      msg_type: 'text',
      content: JSON.stringify({ text }),
    }),
  });

  const data = await res.json();
  if (data.code !== 0) throw new Error(`Send message failed: ${JSON.stringify(data)}`);
  return data.data?.message_id;
}

