/**
 * 创建需求单 + 子需求（UI）
 * 1. 先创建客户端需求单 → 拿到 storyId
 * 2. 再创建 UI 子需求，关联到母单
 */
import { createStory } from './create_story.mjs';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';
import { chromium } from 'playwright';

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const WS_DIR = path.resolve(__dirname, '..');
const COOKIES_FILE = path.join(WS_DIR, 'tapd_cookies_yezhijun.json');
const WORKSPACE_ID = '31253609';
const PARENT_WORKITEM_TYPE_ID = '1131253609001000049';
const ONE_V1_TEMPLATE_ID = '1131253609001000047';

const STEALTH_SCRIPT = `
  Object.defineProperty(navigator, 'webdriver', { get: () => undefined });
  Object.defineProperty(navigator, 'plugins', { get: () => [1, 2, 3, 4, 5] });
  Object.defineProperty(navigator, 'languages', { get: () => ['zh-CN', 'zh', 'en'] });
  Object.defineProperty(navigator, 'hardwareConcurrency', { get: () => 8 });
  window.chrome = { runtime: {} };
`;

// UI 模板：UI[1]、UI验收[2]、策划[9]、QA[10]
const TEMPLATE_ACTIVE_INDEXES = {
  ui: [1, 2, 9, 10],
};

// Step 1: 创建客户端母单
console.log('=== Step 1: 创建客户端需求单 ===');
const parentStory = await createStory({
  title: '优化主界面的设置按钮',
  template: 'client',
  handler: '叶枝君',
});
console.log('客户端需求单 URL:', parentStory.url);

const parentStoryId = parentStory.storyId;
console.log('客户端需求单 ID:', parentStoryId);

// Step 2: 创建 UI 子需求
console.log('\n=== Step 2: 创建 UI 子需求（关联母单） ===');

const cookies = JSON.parse(fs.readFileSync(COOKIES_FILE, 'utf8'));

const browser = await chromium.launch({
  headless: false,
  args: ['--no-sandbox', '--disable-blink-features=AutomationControlled'],
});
const context = await browser.newContext({
  userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
});
await context.addInitScript(STEALTH_SCRIPT);
await context.addCookies(cookies);
const page = await context.newPage();

try {
  const STORY_CREATE_URL = `https://www.tapd.cn/${WORKSPACE_ID}/prong/stories/add`;
  console.log('1/3 Opening story create page...');
  await page.goto(STORY_CREATE_URL, { waitUntil: 'networkidle', timeout: 30000 });
  if (page.url().includes('login')) throw new Error('TAPD session expired');
  await page.waitForTimeout(2000);

  const title = '主界面设置按钮优化 - UI';
  console.log('2/3 Filling fields...');
  await page.fill('#StoryName', title);
  await page.selectOption('#StoryPriority', 'P2');
  await page.selectOption('#StoryModule', { label: '1V1' });
  await page.selectOption('#StoryVersion', { label: '【1V1】正式版本V2.0' });
  await page.waitForTimeout(500);

  // 获取 1v1 模板预设
  const v1Template = await page.evaluate(async ({ wsId, tplId }) => {
    const r = await fetch('/api/entity/workitem_template/get_preset_items?workspace_id=' + wsId + '&template_id=' + tplId, {
      headers: { 'X-Requested-With': 'XMLHttpRequest' }
    });
    const data = JSON.parse(await r.text());
    const items = data?.data?.preset_items_tree || [];
    return items.map(item => ({
      id: item.id,
      name: item.name,
      type_id: item.relate_workitem_type_id,
      template_id: item.relate_template_id,
      owner: item.owner,
      english_name: item.relate_workitem_type_english_name,
      color: item.relate_workitem_type_color,
      preset_relations: JSON.stringify(item.preset_relations || []),
    }));
  }, { wsId: WORKSPACE_ID, tplId: ONE_V1_TEMPLATE_ID });

  console.log(`  Loaded ${v1Template.length} preset items`);

  // QA 处理人追加周以天
  const qaItem = v1Template[10];
  if (qaItem && qaItem.english_name === 'QA') {
    if (!qaItem.owner.includes('周以天')) {
      qaItem.owner = (qaItem.owner || '').replace(/;$/, '') + ';周以天;';
      console.log('  QA owner updated');
    }
  }

  const activeIndexes = TEMPLATE_ACTIVE_INDEXES.ui;

  const result = await page.evaluate(async ({ activeIdxs, tplItems, wsId, parentTypeId, tplId, parentStoryId }) => {
    const form = document.getElementById('FormStory');
    const fd = new FormData(form);

    fd.set('data[Story][workitem_type_id]', parentTypeId);
    fd.set('data[Template][id]', tplId);
    fd.set('data[Story][owner]', '叶枝君');
    fd.set('data[Story][parent_id]', parentStoryId);

    // 删除默认 PresetItems
    const delKeys = Array.from(fd.keys()).filter(k => k.startsWith('data[PresetItems]'));
    for (const k of delKeys) fd.delete(k);

    // 添加 UI 激活项
    const activeSet = new Set(activeIdxs);
    for (let i = 0; i < tplItems.length; i++) {
      if (!activeSet.has(i)) continue;
      const item = tplItems[i];
      const prefix = `data[PresetItems][${i}]`;
      fd.append(prefix + '[id]', item.id);
      fd.append(prefix + '[name]', item.name);
      fd.append(prefix + '[relate_workitem_type_id]', item.type_id);
      fd.append(prefix + '[relate_template_id]', item.template_id);
      fd.append(prefix + '[relation_type]', 'story');
      fd.append(prefix + '[owner]', item.owner);
      fd.append(prefix + '[step]', '');
      fd.append(prefix + '[no_permission]', '0');
      fd.append(prefix + '[no_permission_tip]', '');
      fd.append(prefix + '[relate_workitem_type_english_name]', item.english_name);
      fd.append(prefix + '[relate_workitem_type_color]', item.color);
      fd.append(prefix + '[preset_relations]', item.preset_relations || '');
      fd.append(prefix + '[path]', `${i}::`);
      fd.append(prefix + '[identifier]', item.id);
      fd.append(prefix + '[create_task]', 'true');
      fd.append(prefix + '[can_create]', 'true');
      fd.append(prefix + '[cant_create_reason]', '');
    }

    fd.set('data[save_view]', '提交&查看');

    const resp = await fetch(`/${wsId}/prong/stories/add`, {
      method: 'POST',
      body: fd,
      redirect: 'follow',
    });
    const text = await resp.text();
    const urlMatch = resp.url.match(/story\/detail\/(\d+)|stories\/view\/(\d+)|edit\?id=(\d+)/);
    const htmlMatch = text.match(/\"id\":\"(1131253609\d+)\"/);
    return {
      status: resp.status,
      finalUrl: resp.url,
      storyId: urlMatch ? (urlMatch[1] || urlMatch[2] || urlMatch[3]) : (htmlMatch ? htmlMatch[1] : null),
    };
  }, { activeIdxs: activeIndexes, tplItems: v1Template, wsId: WORKSPACE_ID, parentTypeId: PARENT_WORKITEM_TYPE_ID, tplId: ONE_V1_TEMPLATE_ID, parentStoryId });

  if (result.status !== 200) throw new Error(`Submit failed: status ${result.status}`);

  const childUrl = result.storyId
    ? `https://www.tapd.cn/${WORKSPACE_ID}/prong/stories/view/${result.storyId}`
    : result.finalUrl;

  console.log('\n=== 完成 ===');
  console.log(`📌 母单（客户端）：${parentStory.url}`);
  console.log(`📌 子需求（UI）：${childUrl}`);

  // 输出 JSON 供主进程解析
  console.log('\n---RESULT---');
  console.log(JSON.stringify({
    parentUrl: parentStory.url,
    parentStoryId: parentStory.storyId,
    childUrl,
    childStoryId: result.storyId,
  }));
  console.log('---END---');

} finally {
  await browser.close();
  process.exit(0);
}

